UPDATE runtime_outbox SET status='RETRY',next_retry_at=NOW(),locked_by=NULL,locked_at=NULL,
  last_error_summary='运行时投影领取超时，已安全重新调度'
WHERE status='PROCESSING' AND locked_at < #{olderThan}

mapper.select:
SELECT tenant_id AS tenantId,id AS providerCredentialId,credential_version AS credentialVersion,
       auth_type AS authType,enabled,(deleted_at IS NOT NULL) AS deleted,
       ciphertext,initialization_vector AS initializationVector,encryption_version AS encryptionVersion
FROM provider_credential
WHERE id=#{credentialId}
  AND tenant_id=#{tenantId}


WHERE tm.tenant_id=#{tenantId} AND tm.model_code=#{tenantModelCode} AND route.inbound_protocol=#{inboundProtocol}
  AND tm.deleted_at IS NULL AND route.deleted_at IS NULL

ORDER BY target.id ASC NULLS LAST, credential.id ASC NULLS LAST
